(date: string): string => {
  const d = new Date(date)
  if (Number.isNaN(d.getTime())) {
    throw new TypeError(`Invalid date value: "${date}"`)
  }

  const year = d.getFullYear()
  const month = d.getMonth() + 1
  const day = d.getDate()

  return `${year.toString().padStart(4, '0')}-${month.toString().padStart(2, '0')}-${day.toString().padStart(2, '0')}`
}

export function formatDuration(ms: number | string) {
  ms = Number(ms)
  if (Number.isNaN(ms) || ms < 0)
    return '-'
  if (ms < 1)
    return '<1ms'
  if (ms < 1000)
    return `${ms}ms`
  if (ms < 1000 * 60)
    return `${(ms / 1000).toFixed(2)}s`
  return `${(ms / 1000 / 60).toFixed(2)}min`
}

export function getHslColorFromStringHash(name: string, saturation = 65, lightness = 50, opacity: number | string = 1) {
  let hash = 0
  for (let i = 0; i < name.length; i++)
    hash = name.charCodeAt(i) + ((hash << 5) - hash)
  const h = hash % 360
  return `hsla(${h}, ${saturation}%, ${lightness}%, ${opacity})`
}

function formatFileSize(bytes: number) {
  if (bytes < 1024)
    return `${bytes}B`
  if (bytes < 1024 * 1024)
    return `${(bytes / 1024).toFixed(1)}KB`
  if (bytes < 1024 * 1024 * 1024)
    return `${(bytes / 1024 / 1024).toFixed(1)}MB`
  return `${(bytes / 1024 / 1024 / 1024).toFixed(1)}GB`
}

function sortKeys(a: string, b: string) {
  const indexA = ORDER_KEYS.findIndex(k => typeof k === 'string' ? k === a : k.test(a))
  const indexB = ORDER_KEYS.findIndex(k => typeof k === 'string' ? k === b : k.test(b))
  if (indexA === -1 && indexB !== -1)
    return 1
  if (indexA !== -1 && indexB === -1)
    return -1
  if (indexA < indexB)
    return -1
  if (indexA > indexB)
    return 1
  return a.localeCompare(b)
}

function formatBytes(bytes: number) {
  if (bytes === 0) return '0 Bytes'

  const sizes = ['Bytes', 'KB', 'MB', 'GB']
  const i = Math.floor(Math.log(bytes) / Math.log(1000))
  const formattedSize = (bytes / Math.pow(1000, i)).toFixed(2)

  return `${formattedSize}${sizes[i]}`
}

