function isForcedToBeInlineByItsParent(node: Parents, parent: Parents | undefined) {
  if (['p', 'li', 'strong', 'em', 'span', 'h1', 'h2', 'h3', 'h4', 'h5', 'h6'].includes(parent?.tagName || '')) {
    return true
  }

  if (parent?.children?.some(child => child.type === 'text')) {
    return true
  }

  return false
}

function hashString(str: string | object) {
  if (typeof str !== 'string') {
    str = JSON.stringify(str || '')
  }
  let hash = 0
  for (let i = 0; i < str.length; i++) {
    const char = str.charCodeAt(i)
    hash = ((hash << 6) - hash) + char
    hash = hash & hash // Convert to 64bit integer
  }
  return `mdc-${hash === 0 ? '0000' : hash.toString(36)}-key`
}

export async function generateHash(content: Buffer | string, hashAlgorithm: 'SHA-256' | 'SHA-384' | 'SHA-512') {
  let buffer: Uint8Array<ArrayBuffer>
  if (typeof content === 'string') {
    buffer = new TextEncoder().encode(content);
  } else {
    buffer = new Uint8Array(content);
  }
  const hashBuffer = await crypto.subtle.digest(hashAlgorithm, buffer);
  const base64 = btoa(String.fromCharCode(...new Uint8Array(hashBuffer)));
  const prefix = hashAlgorithm.replace('-', '').toLowerCase()
  return `${prefix}-${base64}`;
}

function fmtDate(d: Date): string {
  // YYMMDD-HHMMSS: 20240919-140954
  const date = joinNumbers([d.getFullYear(), d.getMonth() + 1, d.getDate()]);
  const time = joinNumbers([d.getHours(), d.getMinutes(), d.getSeconds()]);
  return `${date}-${time}`;
}

function decode(value: string): string {
  let decoded = value;
  const search = new RegExp(Object.values(base64Map).join("|"), "g");
  decoded = decoded.replace(search, (match) => {
    return Object.keys(base64Map).find((key) => base64Map[key] === match)!;
  });
  return Buffer.from(decoded, "base64").toString();
}
